def checkAdminPassword(password):
    if len(password) < 8:
        return False
    if not any(c.isupper() for c in password):
        return False
    if not any(c.islower() for c in password):
        return False
    if not any(c.isdigit() for c in password):
        return False
    special_chars = set("!@#$%^&*()-_=+[]{}|;:,.<>/?")
    if not any(c in special_chars for c in password):
        return False
    if any(c.isspace() for c in password):
        return False
    weak_passwords = {'password', '123456', 'qwerty', 'admin', 'letmein', '123456789', '00000000', '11111111', '123123', 'abc123', 'password123', 'pass123', 'pass@word', 'admin123', '12345678', '1234567890'}
    if password.lower() in weak_passwords:
        return False
    return True

